// ============================================
// EMERGENCY CONTROLLER - Circuit Breaker Logic
// ============================================
// Checks multiple safety conditions every 15 min.
// If ANY critical condition triggers -> EMERGENCY STOP ALL ADS.
// If warning condition triggers -> conservative mode (lower bids).

const spendData = $('Fetch Today Total Spend').first().json;
const balanceData = $('Fetch Latest Balance').first().json;
const emergencyData = $('Fetch Emergency State').first().json;
const bidActivity = $('Fetch Bid Activity').first().json;
const anomalyData = $('Fetch Active Anomalies').first().json;

// --- CONFIG ---
const DAILY_BUDGET = 200;           // $200/day (4x from previous $50)
const MIN_BALANCE_CRITICAL = 5;     // $5 = EMERGENCY
const MIN_BALANCE_WARNING = 20;     // $20 = warning
const MAX_BID_CHANGES_PER_HOUR = 30;
const CRITICAL_ANOMALY_THRESHOLD = 3;

// --- Parse data ---
const stats = spendData?.data?.result?.data || spendData?.data || [];
let totalSpendToday = 0;
if (Array.isArray(stats)) {
  stats.forEach(s => { totalSpendToday += Number(s.money) || 0; });
} else if (stats?.money) {
  totalSpendToday = Number(stats.money) || 0;
}

const balance = Number(balanceData?.balance) || 999;
const spendRate = Number(balanceData?.spend_rate_per_hour) || 0;
const hoursRemaining = Number(balanceData?.hours_remaining) || 999;
const isAlreadyEmergency = emergencyData?.is_active === true;
const bidChangesLastHour = Number(bidActivity?.bid_changes_last_hour) || 0;
const activeAnomalies = Number(anomalyData?.active_anomalies) || 0;

const now = new Date();
const hour = now.getHours();
const hoursElapsed = hour + now.getMinutes() / 60;
const budgetUsedPct = (totalSpendToday / DAILY_BUDGET) * 100;

const alerts = [];
let emergencyAction = 'NONE';    // NONE, EMERGENCY_STOP, CONSERVATIVE_MODE, LOWER_ALL
let emergencyReason = '';

// --- LEVEL 6: EMERGENCY STOP ---

// Balance critically low
if (balance < MIN_BALANCE_CRITICAL) {
  emergencyAction = 'EMERGENCY_STOP';
  emergencyReason = `CRITICAL: Balance $${balance.toFixed(2)} < $${MIN_BALANCE_CRITICAL}`;
  alerts.push({ severity: 'critical', msg: emergencyReason });
}

// Spend rate is 3x daily budget pace
if (spendRate > 0 && hoursElapsed > 1) {
  const expectedRatePerHour = DAILY_BUDGET / 24;
  if (spendRate > expectedRatePerHour * 3) {
    emergencyAction = 'EMERGENCY_STOP';
    emergencyReason = `CRITICAL: Spend rate $${spendRate.toFixed(2)}/h is 3x target $${expectedRatePerHour.toFixed(2)}/h`;
    alerts.push({ severity: 'critical', msg: emergencyReason });
  }
}

// Already spent 95% of daily budget with >4h remaining
if (budgetUsedPct >= 95 && (24 - hoursElapsed) > 4) {
  emergencyAction = 'EMERGENCY_STOP';
  emergencyReason = `CRITICAL: ${budgetUsedPct.toFixed(0)}% budget used ($${totalSpendToday.toFixed(2)}/$${DAILY_BUDGET}) with ${(24-hoursElapsed).toFixed(1)}h remaining`;
  alerts.push({ severity: 'critical', msg: emergencyReason });
}

// Too many critical anomalies
if (activeAnomalies >= CRITICAL_ANOMALY_THRESHOLD) {
  emergencyAction = 'EMERGENCY_STOP';
  emergencyReason = `CRITICAL: ${activeAnomalies} unresolved critical anomalies`;
  alerts.push({ severity: 'critical', msg: emergencyReason });
}

// --- LEVEL 4-5: CONSERVATIVE MODE ---
if (emergencyAction === 'NONE') {
  // 80% budget used -> conservative (only lower bids allowed)
  if (budgetUsedPct >= 80 && (24 - hoursElapsed) > 4) {
    emergencyAction = 'CONSERVATIVE_MODE';
    emergencyReason = `WARNING: ${budgetUsedPct.toFixed(0)}% budget used, switching to conservative mode`;
    alerts.push({ severity: 'warning', msg: emergencyReason });
  }
  // Balance warning
  if (balance < MIN_BALANCE_WARNING) {
    emergencyAction = 'CONSERVATIVE_MODE';
    emergencyReason = `WARNING: Balance $${balance.toFixed(2)} < $${MIN_BALANCE_WARNING}`;
    alerts.push({ severity: 'warning', msg: emergencyReason });
  }
  // Less than 4 hours of balance remaining
  if (hoursRemaining < 4 && hoursRemaining > 0) {
    emergencyAction = 'LOWER_ALL';
    emergencyReason = `WARNING: Only ${hoursRemaining.toFixed(1)}h of balance remaining at current rate`;
    alerts.push({ severity: 'warning', msg: emergencyReason });
  }
  // Suspicious bid activity (possible bug)
  if (bidChangesLastHour > MAX_BID_CHANGES_PER_HOUR) {
    emergencyAction = 'CONSERVATIVE_MODE';
    emergencyReason = `WARNING: ${bidChangesLastHour} bid changes in last hour (max: ${MAX_BID_CHANGES_PER_HOUR})`;
    alerts.push({ severity: 'warning', msg: emergencyReason });
  }
}

// --- OUTPUT ---
return [{
  json: {
    action: emergencyAction,
    reason: emergencyReason,
    is_already_emergency: isAlreadyEmergency,
    balance: Math.round(balance * 100) / 100,
    total_spend_today: Math.round(totalSpendToday * 100) / 100,
    daily_budget: DAILY_BUDGET,
    budget_used_pct: Math.round(budgetUsedPct * 10) / 10,
    spend_rate_per_hour: Math.round(spendRate * 100) / 100,
    hours_remaining: Math.round(hoursRemaining * 10) / 10,
    bid_changes_last_hour: bidChangesLastHour,
    active_anomalies: activeAnomalies,
    alerts: alerts,
    checked_at: $now.toISO()
  }
}];

// Collect all active ad IDs for emergency stop
const adsData = $('Fetch Active Ads for STOP').first().json;
const ads = adsData?.data?.result?.data || adsData?.data || (Array.isArray(adsData) ? adsData : []);

if (!Array.isArray(ads) || ads.length === 0) {
  return [{ json: { ad_ids: [], count: 0 } }];
}

const adIds = ads.map(a => a.id).filter(Boolean);

// Batch into groups of 50 for API
const BATCH_SIZE = 50;
const batches = [];
for (let i = 0; i < adIds.length; i += BATCH_SIZE) {
  batches.push(adIds.slice(i, i + BATCH_SIZE));
}

return batches.map(batch => ({
  json: {
    ad_ids: batch,
    ids_string: JSON.stringify(batch),
    count: batch.length,
    total: adIds.length
  }
}));

